    struct PresetDesc {
        const float* fir; float pitch; float ringFc; float ringDepth; float noise;
    };

    // indexed to match AudioEffects effect enum values
    inline const PresetDesc* Get(int eff) {
        static const PresetDesc radio = { FIR_RADIO, 1.0f, 0.0f, 0.0f, 0.0f };
        static const PresetDesc phone = { FIR_PHONE, 1.0f, 0.0f, 0.0f, 0.0f };
        static const PresetDesc pa = { FIR_PA, 1.0f, 0.0f, 0.0f, 0.0f };
        static const PresetDesc muffled = { FIR_MUFFLED, 1.0f, 0.0f, 0.0f, 0.0f };
        static const PresetDesc masked = { FIR_MASKED, 1.0f, 0.0f, 0.0f, 0.0f };
        static const PresetDesc stormtrooper = { FIR_STORMTROOPER, 1.0f, 0.0f, 0.0f, 0.0f };
        static const PresetDesc combine = { FIR_COMBINE, 1.0f, 94.0f, 0.5f, 0.0f };
        switch (eff) {
        case AudioEffects::EFF_RADIO: return &radio;
        case AudioEffects::EFF_PHONE: return &phone;
        case AudioEffects::EFF_PA: return &pa;
        case AudioEffects::EFF_MUFFLED: return &muffled;
        case AudioEffects::EFF_MASKED: return &masked;
        case AudioEffects::EFF_STORMTROOPER: return &stormtrooper;
        case AudioEffects::EFF_COMBINE: return &combine;
        default: return nullptr;
        }
    }
